<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Falling Sand Simulator</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            background-color: #1a1a1a;
            color: #e0e0e0;
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
            padding: 20px;
        }

        .container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 20px;
        }

        h1 {
            font-size: 24px;
            font-weight: 500;
            color: #fff;
        }

        .canvas-wrapper {
            border: 2px solid #333;
            background-color: #0a0a0a;
            padding: 10px;
            border-radius: 4px;
        }

        #sand {
            display: block;
            border: 1px solid #222;
            cursor: crosshair;
            image-rendering: pixelated;
            image-rendering: crisp-edges;
        }

        .controls {
            display: flex;
            flex-direction: column;
            gap: 12px;
            align-items: center;
            width: 100%;
            max-width: 500px;
        }

        .button-group {
            display: flex;
            gap: 8px;
            flex-wrap: wrap;
            justify-content: center;
        }

        button {
            padding: 10px 16px;
            border: none;
            border-radius: 4px;
            font-size: 14px;
            font-weight: 500;
            cursor: pointer;
            transition: all 200ms ease;
            background-color: #333;
            color: #e0e0e0;
            text-transform: uppercase;
            letter-spacing: 0.5px;
        }

        button:hover {
            background-color: #444;
            transform: translateY(-2px);
            box-shadow: 0 4px 8px rgba(0, 0, 0, 0.3);
        }

        button:active {
            transform: translateY(0);
        }

        button.active {
            background-color: #666;
            box-shadow: 0 0 0 2px #888;
        }

        #mat-sand.active {
            background-color: #d4a574;
            color: #000;
        }

        #mat-water.active {
            background-color: #4da6ff;
            color: #000;
        }

        #mat-wall.active {
            background-color: #999;
            color: #000;
        }

        #mat-acid.active {
            background-color: #7fff00;
            color: #000;
        }

        #mat-empty.active {
            background-color: #555;
        }

        #clear {
            background-color: #c33;
            padding: 12px 24px;
        }

        #clear:hover {
            background-color: #e55;
        }

        .info {
            font-size: 12px;
            color: #888;
            text-align: center;
        }
    </style>
</head>
<body>
    <div class="container">
        <h1>Falling Sand Simulator</h1>

        <div class="canvas-wrapper">
            <canvas id="sand" width="400" height="400"></canvas>
        </div>

        <div class="controls">
            <div class="button-group">
                <button id="mat-sand" class="material-btn active">Sand</button>
                <button id="mat-water" class="material-btn">Water</button>
                <button id="mat-wall" class="material-btn">Wall</button>
                <button id="mat-acid" class="material-btn">Acid</button>
                <button id="mat-empty" class="material-btn">Eraser</button>
            </div>
            <button id="clear">Clear All</button>
        </div>

        <div class="info">Click and drag to paint • Select a material first</div>
    </div>

    <script>
        const GRID_W = 100;
        const GRID_H = 100;
        const CELL_SIZE = 4;

        const EMPTY = 'empty';
        const SAND = 'sand';
        const WATER = 'water';
        const WALL = 'wall';
        const ACID = 'acid';

        const COLORS = {
            [EMPTY]: '#0a0a0a',
            [SAND]: '#d4a574',
            [WATER]: '#4da6ff',
            [WALL]: '#999',
            [ACID]: '#7fff00'
        };

        const canvas = document.getElementById('sand');
        const ctx = canvas.getContext('2d');

        let grid = Array(GRID_H).fill(null).map(() => Array(GRID_W).fill(EMPTY));
        let nextGrid = Array(GRID_H).fill(null).map(() => Array(GRID_W).fill(EMPTY));

        let selectedMaterial = SAND;
        let isDrawing = false;

        function sim_tick() {
            for (let y = 0; y < GRID_H; y++) {
                for (let x = 0; x < GRID_W; x++) {
                    nextGrid[y][x] = grid[y][x];
                }
            }

            for (let y = GRID_H - 1; y >= 0; y--) {
                for (let x = 0; x < GRID_W; x++) {
                    const material = grid[y][x];

                    if (material === EMPTY || material === WALL) continue;

                    if (material === SAND) {
                        processParticle_sand(x, y);
                    } else if (material === WATER) {
                        processParticle_water(x, y);
                    } else if (material === ACID) {
                        processParticle_acid(x, y);
                    }
                }
            }

            [grid, nextGrid] = [nextGrid, grid];
        }

        function canMove(x, y, newX, newY, material) {
            if (newX < 0 || newX >= GRID_W || newY < 0 || newY >= GRID_H) {
                return false;
            }
            const target = grid[newY][newX];
            if (target === EMPTY) return true;
            if (target === WATER && material === SAND) return true;
            if (target === ACID && material === SAND) return true;
            if (target === WATER && material === ACID) return true;
            return false;
        }

        function moveParticle(x, y, newX, newY) {
            nextGrid[y][x] = grid[newY][newX];
            nextGrid[newY][newX] = grid[y][x];
        }

        function processParticle_sand(x, y) {
            if (y + 1 < GRID_H) {
                const below = grid[y + 1][x];
                if (below === EMPTY || below === WATER || below === ACID) {
                    moveParticle(x, y, x, y + 1);
                    return;
                }
            }

            const directions = Math.random() < 0.5 ? 
                [[x - 1, y + 1], [x + 1, y + 1]] :
                [[x + 1, y + 1], [x - 1, y + 1]];

            for (const [newX, newY] of directions) {
                if (canMove(x, y, newX, newY, SAND)) {
                    moveParticle(x, y, newX, newY);
                    return;
                }
            }
        }

        function processParticle_water(x, y) {
            if (y + 1 < GRID_H) {
                const below = grid[y + 1][x];
                if (below === EMPTY || below === ACID) {
                    moveParticle(x, y, x, y + 1);
                    return;
                }
            }

            const directions = Math.random() < 0.5 ? 
                [[x - 1, y], [x + 1, y]] :
                [[x + 1, y], [x - 1, y]];

            for (const [newX, newY] of directions) {
                if (canMove(x, y, newX, newY, WATER)) {
                    moveParticle(x, y, newX, newY);
                    return;
                }
            }
        }

        function processParticle_acid(x, y) {
            if (y + 1 < GRID_H) {
                const below = grid[y + 1][x];
                if (below === EMPTY) {
                    moveParticle(x, y, x, y + 1);
                    return;
                }
                if (below === SAND || below === WALL) {
                    nextGrid[y + 1][x] = ACID;
                    nextGrid[y][x] = EMPTY;
                    return;
                }
                if (below === WATER) {
                    moveParticle(x, y, x, y + 1);
                    return;
                }
            }

            const directions = Math.random() < 0.5 ? 
                [[x - 1, y], [x + 1, y]] :
                [[x + 1, y], [x - 1, y]];

            for (const [newX, newY] of directions) {
                if (newX < 0 || newX >= GRID_W || newY < 0 || newY >= GRID_H) continue;
                const target = grid[newY][newX];
                if (target === EMPTY) {
                    moveParticle(x, y, newX, newY);
                    return;
                }
                if (target === SAND || target === WALL) {
                    nextGrid[newY][newX] = ACID;
                    nextGrid[y][x] = EMPTY;
                    return;
                }
                if (target === WATER) {
                    moveParticle(x, y, newX, newY);
                    return;
                }
            }
        }

        function sim_clear() {
            for (let y = 0; y < GRID_H; y++) {
                for (let x = 0; x < GRID_W; x++) {
                    grid[y][x] = EMPTY;
                }
            }
        }

        function render() {
            ctx.fillStyle = COLORS[EMPTY];
            ctx.fillRect(0, 0, canvas.width, canvas.height);

            for (let y = 0; y < GRID_H; y++) {
                for (let x = 0; x < GRID_W; x++) {
                    const material = grid[y][x];
                    if (material !== EMPTY) {
                        ctx.fillStyle = COLORS[material];
                        ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);
                    }
                }
            }
        }

        function animate() {
            sim_tick();
            render();
            requestAnimationFrame(animate);
        }

        animate();

        document.getElementById('mat-sand').addEventListener('click', () => selectMaterial(SAND, 'mat-sand'));
        document.getElementById('mat-water').addEventListener('click', () => selectMaterial(WATER, 'mat-water'));
        document.getElementById('mat-wall').addEventListener('click', () => selectMaterial(WALL, 'mat-wall'));
        document.getElementById('mat-acid').addEventListener('click', () => selectMaterial(ACID, 'mat-acid'));
        document.getElementById('mat-empty').addEventListener('click', () => selectMaterial(EMPTY, 'mat-empty'));

        function selectMaterial(material, buttonId) {
            selectedMaterial = material;
            document.querySelectorAll('.material-btn').forEach(btn => btn.classList.remove('active'));
            document.getElementById(buttonId).classList.add('active');
        }

        document.getElementById('clear').addEventListener('click', () => {
            sim_clear();
        });

        canvas.addEventListener('mousedown', (e) => {
            isDrawing = true;
            paintAtEvent(e);
        });

        canvas.addEventListener('mousemove', (e) => {
            if (!isDrawing) return;
            paintAtEvent(e);
        });

        canvas.addEventListener('mouseup', () => {
            isDrawing = false;
        });

        canvas.addEventListener('mouseleave', () => {
            isDrawing = false;
        });

        function paintAtEvent(e) {
            const rect = canvas.getBoundingClientRect();
            const x = Math.floor((e.clientX - rect.left) / CELL_SIZE);
            const y = Math.floor((e.clientY - rect.top) / CELL_SIZE);
            if (x >= 0 && x < GRID_W && y >= 0 && y < GRID_H) {
                paintBrush(x, y);
            }
        }

        function paintBrush(x, y) {
            for (let dy = -1; dy <= 1; dy++) {
                for (let dx = -1; dx <= 1; dx++) {
                    const nx = x + dx;
                    const ny = y + dy;
                    if (nx >= 0 && nx < GRID_W && ny >= 0 && ny < GRID_H) {
                        grid[ny][nx] = selectedMaterial;
                    }
                }
            }
        }

        window.sim = {
            w: GRID_W,
            h: GRID_H,
            tick: function(n) {
                for (let i = 0; i < n; i++) {
                    sim_tick();
                }
            },
            get: function(x, y) {
                if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) {
                    return EMPTY;
                }
                return grid[y][x];
            },
            set: function(x, y, material) {
                if (x >= 0 && x < GRID_W && y >= 0 && y < GRID_H) {
                    grid[y][x] = material;
                }
            },
            clear: sim_clear
        };
    </script>
</body>
</html>
